import React from 'react';
import { Link } from 'react-router-dom';
import './Home.css';

const Home = () => {
  return (
    <div className="home-container">
      <section className="hero-section">
        <div className="hero-content">
          <h1 className="hero-heading">Discover Knowledge, One Book at a Time.</h1>
          <p className="hero-subheading">Find your next favorite book.</p>
          <p className="hero-description">
            Explore thousands of books in our digital library. Search, borrow, and discover new worlds through literature.
          </p>
          <div className="hero-buttons">
            <Link to="/browse" className="btn-primary">Browse Books</Link>
            <Link to="/about" className="btn-secondary">How It Works</Link>
          </div>
        </div>
        <div className="hero-image">
          <img src="https://via.placeholder.com/600x400?text=Library+Books" alt="Library Books" />
        </div>
      </section>
    </div>
  );
};

export default Home;
